import React from "react";
import ReactDOM from "react-dom";
import { BrowserRouter } from "react-router-dom"; // Ensure this is installed
import App from "./App";

ReactDOM.render(
  <BrowserRouter basename="/IR">  {/* Add the basename */}
    <App />
  </BrowserRouter>,
  document.getElementById("root")
)

